    pub fn parse_fixed_float_value(&self, mut input: Value) -> Value {
        if is_true(&(is_equal(&input, &Value::Null))) || is_true(&(is_equal(&input, &Value::Str("-".to_string())))) {
            return Value::Null;
        }
        if is_equal(&input, &Value::Str("".to_string())) {
            return Value::Int(0);
        }
        let mut isPercentage: Value = Value::Bool(is_greater_than_or_equal(&get_index_of(&input, &Value::Str("%".to_string())), &Value::Int(0)));
        let mut parts: Value = split(&input, &Value::Str(" ".to_string()));
        let mut value: Value = replace_str(&get_value(&parts, &Value::Int(0)), &Value::Str("%".to_string()), &Value::Str("".to_string()));
        let mut result: Value = crate::runtime::parse_float(&value);
        if is_true(&(is_greater_than(&result, &Value::Int(0)))) && is_true(&isPercentage) {
            panic!("{}", crate::exchange_errors::exchange_error(add(&add(&self.id, &Value::Str(" parseFixedFloatValue() detected an unsupported non-zero percentage-based fee ".to_string())), &input)));
        }
        return result;

    Value::Null
}

