    pub fn handle_errors(&self, mut httpCode: Value, mut reason: Value, mut url: Value, mut method: Value, mut headers: Value, mut body: Value, mut response: Value, mut requestHeaders: Value, mut requestBody: Value) -> Value {
        if is_equal(&response, &Value::Null) {
            return Value::Null;
        }
        if is_true(&(Value::Bool(in_op(&response, &Value::Str("error".to_string()))))) && !is_true(&(Value::Bool(in_op(&response, &Value::Str("result".to_string()))))) {
            // error: {
            //     "code": "140434",
            //     "msg": "Your margin balance is not sufficient to place the order for '5 TON'. Please top up your margin wallet by "2.5 USDT"."
            // }
            //
            let mut errorCode: Value = self.safe_value_k(response.clone(), "error", &[Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            })]);
            let mut messageError: Value = self.safe_string_k(errorCode.clone(), "msg", &[]);
            let mut code: Value = self.safe_string_k(errorCode.clone(), "code", &[]);
            let mut feedback: Value = add(&add(&self.id, &Value::Str(" ".to_string())), &body);
            self.throw_exactly_matched_exception(get_value(&self.exceptions, &Value::Str("exact".to_string())), code.clone(), feedback.clone());
            self.throw_broadly_matched_exception(get_value(&self.exceptions, &Value::Str("broad".to_string())), messageError.clone(), feedback.clone());
            panic!("{}", crate::exchange_errors::exchange_error(feedback));
        }
        if is_true(&(Value::Bool(in_op(&response, &Value::Str("result".to_string()))))) || is_true(&(Value::Bool(in_op(&response, &Value::Str("errmsg".to_string()))))) {
            //
            //     {"result":false,"error":"Error 50052: Insufficient funds"}
            //     {"s":"error","errmsg":"strconv.ParseInt: parsing \"\": invalid syntax"}
            //
            let mut success: Value = self.safe_bool_k(response.clone(), "result", &[Value::Bool(false)]);
            if is_string(&success) {
                if is_true(&(is_equal(&success, &Value::Str("true".to_string())))) || is_true(&(is_equal(&success, &Value::Str("1".to_string())))) {
                    success = Value::Bool(true);
                }  else {
                    success = Value::Bool(false);
                }
            }
            if !is_true(&success) {
                let mut code: Value = Value::Null;
                let mut message: Value = self.safe_string2(response.clone(), Value::Str("error".to_string()), Value::Str("errmsg".to_string()), &[]);
                let mut errorParts: Value = split(&message, &Value::Str(":".to_string()));
                let mut numParts: Value = get_array_length(&errorParts);
                if is_greater_than(&numParts, &Value::Int(1)) {
                    let mut errorSubParts: Value = split(&get_value(&errorParts, &Value::Int(0)), &Value::Str(" ".to_string()));
                    let mut numSubParts: Value = get_array_length(&errorSubParts);
                    code = ternary(is_true(&(is_greater_than(&numSubParts, &Value::Int(1)))), get_value(&errorSubParts, &Value::Int(1)), get_value(&errorSubParts, &Value::Int(0)));
                }
                let mut feedback: Value = add(&add(&self.id, &Value::Str(" ".to_string())), &body);
                self.throw_exactly_matched_exception(get_value(&self.exceptions, &Value::Str("exact".to_string())), code.clone(), feedback.clone());
                self.throw_broadly_matched_exception(get_value(&self.exceptions, &Value::Str("broad".to_string())), message.clone(), feedback.clone());
                panic!("{}", crate::exchange_errors::exchange_error(feedback));
            }
        }
        return Value::Null;

    Value::Null
}
